args.sparql:
SELECT ?locationLabel WHERE {
  ?event rdfs:label "Snooker World Open"@en .
  ?event wdt:P131 ?location .
  ?location rdfs:label ?locationLabel .
}

SELECT ?locationLabel WHERE {
  ?event rdfs:label "World Open"@en .
  ?event wdt:P276 ?location .
  ?location rdfs:label ?locationLabel .
  ?event wdt:P511 wd:Q541828 .  # wd:Q541828 is Snooker World Open
}

SELECT ?locationLabel WHERE {
  ?event wdt:P31 wd:Q413528;  # sports event
         wdt:P136 wd:Q178004;  # snooker
         rdfs:label ?eventLabel;
         wdt:P276 ?location.
  ?location rdfs:label ?locationLabel.
  FILTER (CONTAINS(LCASE(STR(?eventLabel)), "world open"))
  FILTER (LANG(?eventLabel) = "en")
  FILTER (LANG(?locationLabel) = "en")
}

SELECT ?locationLabel WHERE {
  ?event rdfs:label "World Open"@en;
         wdt:P136 wd:Q178004;
         wdt:P276 ?location.
  ?location rdfs:label ?locationLabel.
  FILTER (LANG(?locationLabel) = "en")
}

SELECT ?event ?eventLabel WHERE {
  ?event wdt:P31 wd:Q413528;  # sports event
         rdfs:label ?eventLabel;
         wdt:P276 ?location.
  FILTER (CONTAINS(LCASE(STR(?eventLabel)), "world open"))
  FILTER (LANG(?eventLabel) = "en")
  FILTER (EXISTS { ?event wdt:P136 wd:Q178004 })  # ensure it's snooker
}
